import{_ as a,o as t,c as r,a7 as s}from"./chunks/framework.C5fSpjcB.js";const u=JSON.parse('{"title":"Frequently Asked Questions (FAQ)","description":"","frontmatter":{},"headers":[],"relativePath":"en/guides/faq.md","filePath":"en/guides/faq.md","lastUpdated":1775394001000}'),o={name:"en/guides/faq.md"};function i(n,e,l,h,d,c){return t(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="frequently-asked-questions-faq" tabindex="-1">Frequently Asked Questions (FAQ) <a class="header-anchor" href="#frequently-asked-questions-faq" aria-label="Permalink to &quot;Frequently Asked Questions (FAQ)&quot;">​</a></h1><h2 id="general-questions" tabindex="-1">General Questions <a class="header-anchor" href="#general-questions" aria-label="Permalink to &quot;General Questions&quot;">​</a></h2><h3 id="q-what-type-of-game-is-morimens" tabindex="-1">Q: What type of game is Morimens? <a class="header-anchor" href="#q-what-type-of-game-is-morimens" aria-label="Permalink to &quot;Q: What type of game is Morimens?&quot;">​</a></h3><p>A: Morimens (忘却前夜) is a <strong>roguelite deckbuilding gacha game</strong> with Lovecraftian/Cthulhu Mythos themes, developed by B.I.A.V. Studio. It features turn-based card combat, roguelite exploration (Investigation), and a character collection system.</p><h3 id="q-what-platforms-is-the-game-available-on" tabindex="-1">Q: What platforms is the game available on? <a class="header-anchor" href="#q-what-platforms-is-the-game-available-on" aria-label="Permalink to &quot;Q: What platforms is the game available on?&quot;">​</a></h3><p>A: Morimens is available on <strong>mobile (iOS/Android)</strong> and <strong>PC</strong>. Check the official website for the latest platform availability.</p><h3 id="q-what-servers-are-available" tabindex="-1">Q: What servers are available? <a class="header-anchor" href="#q-what-servers-are-available" aria-label="Permalink to &quot;Q: What servers are available?&quot;">​</a></h3><p>A: Four servers are available:</p><table tabindex="0"><thead><tr><th>Server</th><th>Badge</th><th>Language</th></tr></thead><tbody><tr><td>China (CN)</td><td><span class="server-badge server-cn">CN</span></td><td>Simplified Chinese</td></tr><tr><td>Global</td><td><span class="server-badge server-global">Global</span></td><td>English + others</td></tr><tr><td>Japan (JP)</td><td><span class="server-badge server-jp">JP</span></td><td>Japanese</td></tr><tr><td>Taiwan (TW)</td><td><span class="server-badge server-tw">TW</span></td><td>Traditional Chinese</td></tr></tbody></table><h3 id="q-what-are-the-differences-between-servers" tabindex="-1">Q: What are the differences between servers? <a class="header-anchor" href="#q-what-are-the-differences-between-servers" aria-label="Permalink to &quot;Q: What are the differences between servers?&quot;">​</a></h3><p>A: The core game content is the same across all servers, but the following may differ:</p><ul><li><strong>Content schedule</strong> -- CN is the most ahead; other servers follow.</li><li><strong>Event timing</strong> -- Events may run at different times per server.</li><li><strong>JP rebalancing</strong> -- The JP server has received specific balance adjustments to certain Awakeners and cards. Some characters may perform differently on JP compared to other servers.</li><li><strong>Localization</strong> -- Each server has its own language and may have minor localized content differences.</li></ul><h3 id="q-what-is-the-jp-rebalance" tabindex="-1">Q: What is the JP rebalance? <a class="header-anchor" href="#q-what-is-the-jp-rebalance" aria-label="Permalink to &quot;Q: What is the JP rebalance?&quot;">​</a></h3><p>A: The Japanese server has implemented balance changes that adjust the power level of certain Awakeners and cards. These changes are specific to the JP server and do not apply to CN, Global, or TW. If you play on JP, check JP-specific tier lists and guides.</p><h2 id="gacha-summoning" tabindex="-1">Gacha / Summoning <a class="header-anchor" href="#gacha-summoning" aria-label="Permalink to &quot;Gacha / Summoning&quot;">​</a></h2><h3 id="q-what-is-the-ssr-rate" tabindex="-1">Q: What is the SSR rate? <a class="header-anchor" href="#q-what-is-the-ssr-rate" aria-label="Permalink to &quot;Q: What is the SSR rate?&quot;">​</a></h3><p>A: The SSR pull rate is <strong>3%</strong>. This was <strong>increased from the original 1%</strong> during development, making Morimens one of the more generous gacha games available.</p><h3 id="q-what-is-the-pity-system" tabindex="-1">Q: What is the pity system? <a class="header-anchor" href="#q-what-is-the-pity-system" aria-label="Permalink to &quot;Q: What is the pity system?&quot;">​</a></h3><p>A: The hard pity is at <strong>30 pulls</strong>. If you do not pull an SSR within 30 pulls, the 30th pull is guaranteed to be SSR. Pity carries over between banners of the same type.</p><h3 id="q-should-i-reroll" tabindex="-1">Q: Should I reroll? <a class="header-anchor" href="#q-should-i-reroll" aria-label="Permalink to &quot;Q: Should I reroll?&quot;">​</a></h3><p>A: Rerolling is optional. The 3% SSR rate and 30-pull pity make it relatively easy to obtain SSR characters through normal play. If you want a specific starting Awakener, rerolling can save time, but it is not necessary.</p><h2 id="gameplay" tabindex="-1">Gameplay <a class="header-anchor" href="#gameplay" aria-label="Permalink to &quot;Gameplay&quot;">​</a></h2><h3 id="q-how-does-combat-work" tabindex="-1">Q: How does combat work? <a class="header-anchor" href="#q-how-does-combat-work" aria-label="Permalink to &quot;Q: How does combat work?&quot;">​</a></h3><p>A: Morimens uses <strong>turn-based card combat</strong>:</p><ul><li><strong>5 Arithmetica per turn</strong> to play cards.</li><li>Each Awakener has <strong>4 Command Cards + 1 Spirit Awakening Card</strong>.</li><li><strong>Madness Points</strong> build to 100 for a free Madness Burst.</li><li><strong>Silver Key</strong> builds to 1000 to activate Key Orders.</li></ul><p>See <a href="./../modes/combat.html">Combat System</a> for full details.</p><h3 id="q-what-is-the-preservation-promise" tabindex="-1">Q: What is the preservation promise? <a class="header-anchor" href="#q-what-is-the-preservation-promise" aria-label="Permalink to &quot;Q: What is the preservation promise?&quot;">​</a></h3><p>A: The &quot;preservation promise&quot; refers to the narrative vow made by the Keeper (player character) to protect and preserve the Awakeners. It is a central theme of the story and influences the relationship between the player and their characters. It also reflects the developers&#39; approach to character treatment in the narrative.</p><h3 id="q-how-many-cards-are-in-the-game" tabindex="-1">Q: How many cards are in the game? <a class="header-anchor" href="#q-how-many-cards-are-in-the-game" aria-label="Permalink to &quot;Q: How many cards are in the game?&quot;">​</a></h3><p>A: Morimens features <strong>185+ cards</strong> across all realms and types, with new cards added alongside each new Awakener release. Each card can be upgraded up to <strong>6 times</strong>.</p><h3 id="q-what-are-the-four-realms" tabindex="-1">Q: What are the four realms? <a class="header-anchor" href="#q-what-are-the-four-realms" aria-label="Permalink to &quot;Q: What are the four realms?&quot;">​</a></h3><p>A: The four Designated Realms are:</p><ul><li><span class="realm-badge realm-chaos">Chaos</span> -- Flexible cross-realm mixing, Silver Key acceleration</li><li><span class="realm-badge realm-aequor">Aequor</span> -- Deep-sea Tentacle summoning</li><li><span class="realm-badge realm-caro">Caro</span> -- Embryo card creation and consumption</li><li><span class="realm-badge realm-ultra">Ultra</span> -- Extra turns from playing cards</li></ul><p>See <a href="./../realms/">Realms Overview</a>.</p><h3 id="q-when-does-phase-chess-unlock" tabindex="-1">Q: When does Phase Chess unlock? <a class="header-anchor" href="#q-when-does-phase-chess-unlock" aria-label="Permalink to &quot;Q: When does Phase Chess unlock?&quot;">​</a></h3><p>A: Phase Chess unlocks after clearing <strong>Stage 3-2</strong> in the main story.</p><h2 id="account-and-technical" tabindex="-1">Account and Technical <a class="header-anchor" href="#account-and-technical" aria-label="Permalink to &quot;Account and Technical&quot;">​</a></h2><h3 id="q-how-can-i-contribute-to-this-wiki" tabindex="-1">Q: How can I contribute to this Wiki? <a class="header-anchor" href="#q-how-can-i-contribute-to-this-wiki" aria-label="Permalink to &quot;Q: How can I contribute to this Wiki?&quot;">​</a></h3><p>A: You can contribute in the following ways:</p><ol><li>Submit a Pull Request on GitHub</li><li>Report errors via Issues</li><li>Share game data in the community</li></ol><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./beginner.html">Beginner Guide</a></li><li><a href="./../modes/combat.html">Combat System</a></li><li><a href="./../modes/gacha.html">Gacha / Summoning</a></li><li><a href="./../realms/">Realms Overview</a></li></ul>',42)])])}const p=a(o,[["render",i]]);export{u as __pageData,p as default};
